#!/usr/bin/env node
/**
 * Generates src/js/00_prng_core_bundle.js from lib/*.core.js
 *
 * Each core module is stripped of ES module syntax (import/export) and
 * concatenated into a single IIFE. A window._XxxCore = {...} assignment
 * is appended after each module's exports, derived from its export list.
 *
 * Config below maps each core file to its window global name and the
 * exact set of names to expose.
 */

import { readFileSync, writeFileSync } from "fs";
import { resolve, dirname } from "path";
import { fileURLToPath } from "url";

const __dir = dirname(fileURLToPath(import.meta.url));
const ROOT  = resolve(__dir, "..");

const CORES = [
    {
        file:   "lib/prng.core.js",
        global: "_PRNGCore",
        exports: ["hash", "makeXoshiro128ss", "seedFromString"],
    },
    {
        file:   "lib/library.core.js",
        global: "_LibraryCore",
        exports: [
            "DIRS", "BOTTOM_FLOOR", "SEGMENT_BOOK_COUNT", "BOOKS_PER_GALLERY",
            "GALLERIES_PER_SEGMENT", "isRestArea", "locationKey", "generateSegment",
            "availableMoves", "applyMove", "describeLocation",
        ],
    },
    {
        file:   "lib/book.core.js",
        global: "_BookCore",
        exports: [
            "PAGES_PER_BOOK", "LINES_PER_PAGE", "CHARS_PER_LINE", "CHARS_PER_PAGE",
            "CHARS_PER_BOOK", "CHARSET", "generateBookPage", "bookMeta", "findCoherentFragment",
        ],
    },
    {
        file:   "lib/lifestory.core.js",
        global: "_LifeStoryCore",
        exports: ["generateLifeStory", "formatLifeStory"],
    },
    {
        file:   "lib/survival.core.js",
        global: "_SurvivalCore",
        exports: [
            "STAT_MAX", "STAT_MIN", "defaultStats", "applyMove",
            "applySleep", "applyEat", "applyDrink",
            "severity", "getWarnings",
        ],
    },
];

function transformCore(src) {
    return src
        .split("\n")
        // Remove import lines
        .filter(line => !/^\s*import\s/.test(line))
        // Strip `export` keyword from declarations, remove bare `export {}`
        .map(line => {
            if (/^\s*export\s*\{[^}]*\}\s*;?\s*$/.test(line)) return null;
            return line.replace(/^\s*export\s+(default\s+)?/, "");
        })
        .filter(line => line !== null)
        .join("\n");
}

const sections = CORES.map(({ file, global, exports: names }) => {
    const src = readFileSync(resolve(ROOT, file), "utf8");
    const body = transformCore(src);
    const assignment = `    window.${global} = { ${names.join(", ")} };`;
    // Strip leading doc comment to avoid duplication — keep the code
    const stripped = body.replace(/^\/\*\*[\s\S]*?\*\/\s*/m, "").trimEnd();
    // Indent each line by 4 spaces
    const indented = stripped.split("\n").map(l => l ? "    " + l : "").join("\n");
    return `    // ---- ${global} ----\n\n${indented}\n\n${assignment}`;
});

const banner = `/* Browser bundle — generated by scripts/build-bundle.js
 * DO NOT EDIT BY HAND. Edit lib/*.core.js and run: node scripts/build-bundle.js
 * Prefixed 00_ so tweego includes it before wrappers (alphabetical order).
 */`;

const output = `${banner}\n\n(function () {\n    "use strict";\n\n${sections.join("\n\n")}\n}());\n`;

const outPath = resolve(ROOT, "src/js/00_prng_core_bundle.js");
writeFileSync(outPath, output, "utf8");
console.log(`Written: src/js/00_prng_core_bundle.js`);
